return[{json:{chatId:n4.chatId,combinedText,claudeBody:n4.claudeBody||visionBody,historyJson:n4.historyJson,visionBody}}];

const n4=$('Soy el ultimo + Contexto').item.json;
let combinedText=n4.combinedText;
try{const inj=$('Inyectar oferta al prompt').item.json;if(inj&&inj.combinedText)combinedText=inj.combinedText;}catch(e){}
