const n4pendingPostulacion=n4.pendingPostulacion?JSON.parse(n4.pendingPostulacion):null;

if(n4pendingEmail&&!n4pendingPostulacion&&CONFIRMAR_EMAIL.test(userTextRaw)){
  pendingAction={type:'SEND_EMAIL',data:n4pendingEmail};
  delete sd.pendingEmail[n4.chatId];
  cleanResponse='✅ Enviando correo a '+n4pendingEmail.to+'...';
} else if(n4pendingEmail&&!n4pendingPostulacion&&CANCELAR_EMAIL.test(userTextRaw)){
  delete sd.pendingEmail[n4.chatId];
  cleanResponse='Correo cancelado.';
} else {
  const PREVIEW_REGEX=/\[\[PREVIEW_LISTO:([\s\S]*?)\]\]/;
  const EJECUTAR_REGEX=/\[\[EJECUTAR_ENVIO\]\]/;
  const GUARDAR_REGEX=/\[\[GUARDAR_MEMORIA:([\s\S]*?)\]\]/;
  const BUSQUEDA_REGEX=/\[\[EJECUTAR_BUSQUEDA\]\]/;
  const CORREO_REGEX=/\[{1,2}(?:ENVIAR|EJECUTAR)_CORREO:([\w.+\-@]+):([^\]\n]+)\]{1,2}/;
  if(cleanResponse.includes('[VOZ_ON]')){sd.voiceMode[n4.chatId]=true;cleanResponse=cleanResponse.replace(/\[VOZ_ON\]/g,'').trim();}
  if(cleanResponse.includes('[VOZ_OFF]')){sd.voiceMode[n4.chatId]=false;cleanResponse=cleanResponse.replace(/\[VOZ_OFF\]/g,'').trim();}
