  const previewMatch=cleanResponse.match(PREVIEW_REGEX);
  const ejecutarMatch=cleanResponse.match(EJECUTAR_REGEX);
  const correoMatch=cleanResponse.match(CORREO_REGEX);
  if(guardarMatch){
    const rawGuardar=guardarMatch[1].trim();
    try{memGuardarPayload=JSON.parse(rawGuardar);}catch(e){memGuardarPayload={nota:rawGuardar.replace(/[{}"]/g,'').trim().slice(0,500),seccion:'Notas de Comportamiento'};}
    cleanResponse=cleanResponse.replace(GUARDAR_REGEX,'').trim();
  }
  if(previewMatch){try{const pd=JSON.parse(previewMatch[1]);sd.pendingPostulacion[n4.chatId]={...pd,chatId:n4.chatId,timestamp:Date.now()};cleanResponse=cleanResponse.replace(PREVIEW_REGEX,'').trim();}catch(e){}}
  if(ejecutarMatch){const pending=sd.pendingPostulacion[n4.chatId]||null;if(pending){pendingAction={type:'SEND_APPLICATION',data:pending};delete sd.pendingPostulacion[n4.chatId];cleanResponse='Registrando postulacion en Notion...';}else{cleanResponse='No hay postulacion pendiente.';}}
  const busquedaMatch=cleanResponse.match(BUSQUEDA_REGEX);
  if(busquedaMatch){triggerWF01=true;cleanResponse=cleanResponse.replace(BUSQUEDA_REGEX,'').trim();}
  if(correoMatch){
    const emailTo=correoMatch[1].trim();
    const emailSubject=correoMatch[2].trim();
    let emailBody=cleanResponse.replace(CORREO_REGEX,'').trim();
    emailBody=emailBody
      .replace(/\[{1,2}(?:ENVIAR|EJECUTAR)_CORREO[^\]]*\]{1,2}/g,'')
      .replace(/<<<[^\n]*/g,'')
      .replace(/\n{3,}/g,'\n\n')
      .trim();
    sd.pendingEmail[n4.chatId]={to:emailTo,subject:emailSubject,body:emailBody,chatId:n4.chatId,timestamp:Date.now()};
    cleanResponse=emailBody;
  }
  cleanResponse=cleanResponse
    .replace(/\[{1,2}(?:ENVIAR|EJECUTAR)_CORREO:[^\]\n]+\]{1,2}/g,'')
    .replace(/\[{1,2}EJECUTAR_BUSQUEDA\]{1,2}/g,'')
    .replace(/\[{1,2}GUARDAR_MEMORIA\s*:[^\]]*\]{1,2}/g,'')
    .replace(/<<<[^>]*>>>/gs,'')
    .replace(/<<<[^\n]*/g,'')
    .replace(/\n{3,}/g,'\n\n')
    .trim();
}

