  if(!c||c.length<3)return false;
  if(/^\[{1,2}[A-Z_]+[\]:]/.test(c)&&c.length<100)return false;
  if(c.includes('[USUARIO CONFIRMO')||c.includes('Emite [[EJECUTAR_CORREO]]'))return false;
  return true;
});
sd.conversations[n4.chatId]=filteredHistory.slice(-16);
const hasPreview=hasEmailPreview&&!pendingAction;
