const n4=$('Soy el ultimo + Contexto').item.json;
const pages=(nr.results||[]);
let offerContext='';
let notionPageId=null;
if(pages.length>0){
  const page=pages[0];
  const props=page.properties||{};
  const cargo=(props['Nombre']?.title||[]).map(t=>t.plain_text).join('')||'Sin cargo';
