  const to = (d.to && d.to !== 'DESTINATARIO' && d.to.includes('@')) ? d.to : '';
  payload.jobTitle = (d.to && d.to.includes('@')) ? d.to : (d.subject || 'Correo enviado');
  payload.company = to;
  payload.recipientEmail = to;
  payload.emailBody = d.body || '';
  payload.emailSubject = d.subject || '';
  payload.link = '';
  payload.metodo = 'Email directo';
