  payload.recipientEmail = d.emailDestino || '';
  payload.emailBody = d.body || '';
  payload.emailSubject = d.subject || '';
  payload.link = d.link || '';
  payload.metodo = 'Email directo';
  payload.estado = 'Enviado';
  payload.observaciones = d.observaciones || '';
  payload.recordType = 'postulacion';
