let response=$input.first().json?.choices?.[0]?.message?.content||'Error procesando tu mensaje.';
if(response.length>3500)response=response.substring(0,3500)+'...';
const sd=$getWorkflowStaticData('global');
if(!sd.conversations)sd.conversations={};
if(!sd.pendingPostulacion)sd.pendingPostulacion={};
if(!sd.pendingEmail)sd.pendingEmail={};
if(!sd.voiceMode)sd.voiceMode={};
let pendingAction=null,memGuardarPayload=null,cleanResponse=response,triggerWF01=false;

const userTextRaw=(n4.combinedText||'').trim();
const CONFIRMAR_EMAIL=/^(si|s[í]|envialo|env[í]alo|si\s+envialo|m[á]ndalo|mandalo|dale|hazlo|confirmar|ok|enviar|ya\s+te\s+dije|listo|hazlo|procede|confirmo)/i;
const CANCELAR_EMAIL=/^(no|cancelar|no\s+gracias|cancelado)/i;
const n4pendingEmail=n4.pendingEmail?JSON.parse(n4.pendingEmail):null;
const n4pendingPostulacion=n4.pendingPostulacion?JSON.parse(n4.pendingPostulacion):null;

if(n4pendingEmail&&!n4pendingPostulacion&&CONFIRMAR_EMAIL.test(userTextRaw)){
  pendingAction={type:'SEND_EMAIL',data:n4pendingEmail};
  delete sd.pendingEmail[n4.chatId];
  cleanResponse='✅ Enviando correo a '+n4pendingEmail.to+'...';
} else if(n4pendingEmail&&!n4pendingPostulacion&&CANCELAR_EMAIL.test(userTextRaw)){
  delete sd.pendingEmail[n4.chatId];
  cleanResponse='Correo cancelado.';
} else {
  const PREVIEW_REGEX=/\[\[PREVIEW_LISTO:([\s\S]*?)\]\]/;
  const EJECUTAR_REGEX=/\[\[EJECUTAR_ENVIO\]\]/;
  const GUARDAR_REGEX=/\[\[GUARDAR_MEMORIA:([\s\S]*?)\]\]/;
  const BUSQUEDA_REGEX=/\[\[EJECUTAR_BUSQUEDA\]\]/;
  const CORREO_REGEX=/\[{1,2}(?:ENVIAR|EJECUTAR)_CORREO:([\w.+\-@]+):([^\]\n]+)\]{1,2}/;
  if(cleanResponse.includes('[VOZ_ON]')){sd.voiceMode[n4.chatId]=true;cleanResponse=cleanResponse.replace(/\[VOZ_ON\]/g,'').trim();}
  if(cleanResponse.includes('[VOZ_OFF]')){sd.voiceMode[n4.chatId]=false;cleanResponse=cleanResponse.replace(/\[VOZ_OFF\]/g,'').trim();}
  const guardarMatch=cleanResponse.match(GUARDAR_REGEX);
  const previewMatch=cleanResponse.match(PREVIEW_REGEX);
  const ejecutarMatch=cleanResponse.match(EJECUTAR_REGEX);
  const correoMatch=cleanResponse.match(CORREO_REGEX);
  if(guardarMatch){
    const rawGuardar=guardarMatch[1].trim();
    try{memGuardarPayload=JSON.parse(rawGuardar);}catch(e){memGuardarPayload={nota:rawGuardar.replace(/[{}"]/g,'').trim().slice(0,500),seccion:'Notas de Comportamiento'};}
    cleanResponse=cleanResponse.replace(GUARDAR_REGEX,'').trim();
  }
  if(previewMatch){try{const pd=JSON.parse(previewMatch[1]);sd.pendingPostulacion[n4.chatId]={...pd,chatId:n4.chatId,timestamp:Date.now()};cleanResponse=cleanResponse.replace(PREVIEW_REGEX,'').trim();}catch(e){}}
  if(ejecutarMatch){const pending=sd.pendingPostulacion[n4.chatId]||null;if(pending){pendingAction={type:'SEND_APPLICATION',data:pending};delete sd.pendingPostulacion[n4.chatId];cleanResponse='Registrando postulacion en Notion...';}else{cleanResponse='No hay postulacion pendiente.';}}
  const busquedaMatch=cleanResponse.match(BUSQUEDA_REGEX);
  if(busquedaMatch){triggerWF01=true;cleanResponse=cleanResponse.replace(BUSQUEDA_REGEX,'').trim();}
  if(correoMatch){
    const emailTo=correoMatch[1].trim();
    const emailSubject=correoMatch[2].trim();
    let emailBody=cleanResponse.replace(CORREO_REGEX,'').trim();
    emailBody=emailBody
      .replace(/\[{1,2}(?:ENVIAR|EJECUTAR)_CORREO[^\]]*\]{1,2}/g,'')
      .replace(/<<<[^\n]*/g,'')
      .replace(/\n{3,}/g,'\n\n')
      .trim();
    sd.pendingEmail[n4.chatId]={to:emailTo,subject:emailSubject,body:emailBody,chatId:n4.chatId,timestamp:Date.now()};
    cleanResponse=emailBody;
  }
  cleanResponse=cleanResponse
    .replace(/\[{1,2}(?:ENVIAR|EJECUTAR)_CORREO:[^\]\n]+\]{1,2}/g,'')
    .replace(/\[{1,2}EJECUTAR_BUSQUEDA\]{1,2}/g,'')
    .replace(/\[{1,2}GUARDAR_MEMORIA\s*:[^\]]*\]{1,2}/g,'')
    .replace(/<<<[^>]*>>>/gs,'')
    .replace(/<<<[^\n]*/g,'')
    .replace(/\n{3,}/g,'\n\n')
    .trim();
}

const hasEmailPreview=!!sd.pendingEmail[n4.chatId];
const emailData=sd.pendingEmail[n4.chatId]||null;
const emailPreviewText=emailData?('📧 Para: '+emailData.to+'\nAsunto: '+emailData.subject+'\n\n¿Envío este correo?'):null;
const hasAudio=n4.hasAudio===true;
const voiceModeActive=sd.voiceMode[n4.chatId]===true;
const isSimpleShort=cleanResponse.length<80&&!cleanResponse.includes('**')&&!cleanResponse.includes('\n');
let responderConVoz=false;
if(hasAudio)responderConVoz=true;
else if(voiceModeActive)responderConVoz=true;
else if(isSimpleShort&&Math.random()<0.4)responderConVoz=true;
const history=JSON.parse(n4.historyJson);
const newHistory=[...history,{role:'user',content:combinedText||'[audio]'},{role:'assistant',content:cleanResponse}];
const filteredHistory=newHistory.filter(entry=>{
  const c=(entry.content||'').trim();
  if(!c||c.length<3)return false;
  if(/^\[{1,2}[A-Z_]+[\]:]/.test(c)&&c.length<100)return false;
  if(c.includes('[USUARIO CONFIRMO')||c.includes('Emite [[EJECUTAR_CORREO]]'))return false;
  return true;
});
sd.conversations[n4.chatId]=filteredHistory.slice(-16);
const hasPreview=hasEmailPreview&&!pendingAction;
return[{json:{chatId:n4.chatId,response:cleanResponse,cleanResponse,responderConVoz,pendingAction:pendingAction?JSON.stringify(pendingAction):null,memGuardarPayload:memGuardarPayload?JSON.stringify(memGuardarPayload):null,triggerWF01,hasPreview,hasEmailPreview:hasPreview,emailPreviewText}}];

